-- Case 009: masking policy, row access policy, tags, and protected table DDL
CREATE OR REPLACE MASKING POLICY GOVERNANCE.MASK_EMAIL_CONDITIONAL AS(email_value STRING,tenant_id STRING) RETURNS STRING -> CASE WHEN IS_ROLE_IN_SESSION( 'SECURITY_ADMIN') THEN email_value WHEN EXISTS(SELECT 1 FROM GOVERNANCE.TENANT_PRIVILEGE_MAP AS m WHERE m.tenant_id = tenant_id AND IS_DATABASE_ROLE_IN_SESSION(m.database_role_name)) THEN email_value WHEN email_value IS NULL THEN NULL ELSE REGEXP_REPLACE(email_value, '(^.).*(@.*$)', '\\1***\\2') END COMMENT = 'Conditional email masking / メールマスク / إخفاء البريد' EXEMPT_OTHER_POLICIES = TRUE; CREATE OR REPLACE ROW ACCESS POLICY GOVERNANCE.RAP_TENANT_REGION AS(tenant_id STRING,region STRING) RETURNS BOOLEAN -> IS_ROLE_IN_SESSION( 'ACCOUNTADMIN') OR EXISTS(SELECT 1 FROM GOVERNANCE.ROLE_TENANT_REGION_MAP AS m WHERE m.database_role_name = CURRENT_ROLE() AND m.tenant_id = tenant_id AND(m.region = region OR m.region = '*')) COMMENT = 'Tenant and region row access policy'; CREATE OR REPLACE TABLE CORE.PROTECTED_CUSTOMER_PROFILE(customer_id STRING NOT NULL COMMENT 'surrogate customer id',tenant_id STRING NOT NULL,region STRING NOT NULL,email STRING WITH MASKING POLICY GOVERNANCE.MASK_EMAIL_CONDITIONAL USING(email,tenant_id),display_name STRING,locale STRING DEFAULT 'und',profile VARIANT,created_at TIMESTAMP_TZ DEFAULT CURRENT_TIMESTAMP(),updated_at TIMESTAMP_TZ,CONSTRAINT PK_PROTECTED_CUSTOMER_PROFILE PRIMARY KEY(customer_id) NOT ENFORCED) CLUSTER BY(tenant_id,region,DATE_TRUNC( 'day',created_at)) ROW ACCESS POLICY GOVERNANCE.RAP_TENANT_REGION ON(tenant_id,region) WITH TAG(GOVERNANCE.DATA_CLASSIFICATION = 'confidential',GOVERNANCE.OWNER = 'customer-platform') COMMENT = 'Protected customer profile table with masking and row access policy';
